package com.hospital.management.controller.medical;import com.hospital.management.service.MedicalRecordService;import org.junit.jupiter.api.Test;import javax.servlet.http.*;import static org.mockito.Mockito.*;
class MedicalRecordServletTest {@Test void viewRejectsInvalidId()throws Exception{MedicalRecordService s=mock(MedicalRecordService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);when(q.getParameter("id")).thenReturn("invalid");new MedicalRecordViewServlet(s).doGet(q,r);verify(r).sendError(404);verifyNoInteractions(s);}@Test void createRejectsMissingAppointment()throws Exception{MedicalRecordService s=mock(MedicalRecordService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);new MedicalRecordCreateServlet(s,mock(com.hospital.management.service.AppointmentService.class)).doGet(q,r);verify(r).sendError(400);}}
